using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): check-without-throwing ---

// 2a. With the default reflection resolver every type succeeds:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded – type: {found!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> returned false (unexpected)");

// 2b. Build options that only know about Person (source-gen context).
//     Asking for an unknown type (int[]) returns false instead of throwing.
var limited = new JsonSerializerOptions { TypeInfoResolver = SmallContext.Default };

if (limited.TryGetTypeInfo<int[]>(out JsonTypeInfo<int[]>? missing))
    Console.WriteLine($"TryGetTypeInfo<int[]> succeeded – {missing!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<int[]> returned false – metadata not available (expected)");

// Types used by the demo
public record Person(string Name, int Age);

// A source-generated context that only resolves Person
[JsonSerializable(typeof(Person))]
public partial class SmallContext : JsonSerializerContext;

